import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  FiArrowLeft, FiActivity, FiTarget, FiZap,
  FiTrendingUp, FiMessageSquare, FiBell, FiShield, FiClock,
  FiMap, FiAward
} from 'react-icons/fi';

// Modular feature components
import DecayTracker from '../components/SkillDetails/DecayTracker';
import RoleRoadmap from '../components/SkillDetails/RoleRoadmap';
import GapForecast from '../components/SkillDetails/GapForecast';
import SkillRecommendations from '../components/SkillDetails/SkillRecommendations';
import ROIEstimation from '../components/SkillDetails/ROIEstimation';
import AIMentorChat from '../components/SkillDetails/AIMentorChat';
import TrendAlerts from '../components/SkillDetails/TrendAlerts';
import ResilienceScore from '../components/SkillDetails/ResilienceScore';

const SkillDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('decay');

  const features = [
    { id: 'decay', label: 'Skill Decay Tracker', icon: <FiClock /> },
    { id: 'roadmap', label: 'Future Role & Roadmap', icon: <FiMap /> },
    { id: 'gap', label: 'Skill Gap Forecast', icon: <FiActivity /> },
    { id: 'recommend', label: 'Priority Recommendations', icon: <FiTarget /> },
    { id: 'roi', label: 'Learning ROI', icon: <FiTrendingUp /> },
    { id: 'mentor', label: 'AI Mentor', icon: <FiMessageSquare /> },
    { id: 'alerts', label: 'Trend Alerts', icon: <FiBell /> },
    { id: 'resilience', label: 'Resilience Score', icon: <FiShield /> },
  ];

  const renderContent = () => {
    switch (activeTab) {
      case 'decay':
        return <DecayTracker />;
      case 'roadmap':
        return <RoleRoadmap />;
      case 'gap':
        return <GapForecast />;
      case 'recommend':
        return <SkillRecommendations />;
      case 'roi':
        return <ROIEstimation />;
      case 'mentor':
        return <AIMentorChat />;
      case 'alerts':
        return <TrendAlerts />;
      case 'resilience':
        return <ResilienceScore />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Top Nav / Toolbar */}
      <nav className="bg-white border-b border-gray-200 sticky top-0 z-20 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 overflow-x-auto">
          <div className="flex items-center h-16 whitespace-nowrap scrollbar-hide">
            <button
              onClick={() => navigate('/skills')}
              className="mr-6 p-2 hover:bg-gray-100 rounded-lg text-gray-500 transition-colors"
            >
              <FiArrowLeft size={20} />
            </button>
            <div className="flex gap-1">
              {features.map((feature) => (
                <button
                  key={feature.id}
                  onClick={() => setActiveTab(feature.id)}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-all duration-200 ${
                    activeTab === feature.id
                      ? 'bg-blue-600 text-white shadow-md'
                      : 'text-gray-500 hover:bg-gray-100'
                  }`}
                >
                  {feature.icon}
                  <span>{feature.label}</span>
                </button>
              ))}
            </div>
          </div>
        </div>
      </nav>

      {/* Header with Skill Name */}
      <div className="bg-gradient-to-r from-blue-900 to-indigo-900 text-white py-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center gap-4 mb-2 opacity-80">
            <FiAward className="text-yellow-400" />
            <span className="text-xs font-bold uppercase tracking-[0.2em]">Detailed Analysis</span>
          </div>
          <h1 className="text-4xl font-extrabold tracking-tight">
            Skill Analytics: {id?.replace(/-/g, ' ')}
          </h1>
          <p className="mt-2 text-blue-100 opacity-80 max-w-2xl">
            Deep dive into your career trajectory, market value, and AI-driven growth path.
          </p>
        </div>
      </div>

      {/* Main Content Area */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          {/* Active Feature Content */}
          <div className="lg:col-span-8">
            {renderContent()}
          </div>

          {/* Side Overview / Quick Context */}
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
              <h4 className="font-bold text-gray-900 mb-4">Quick Stats</h4>
              <div className="space-y-4">
                <div className="flex justify-between items-center py-2 border-b border-gray-50">
                  <span className="text-gray-500 text-sm">Market Demand</span>
                  <span className="text-green-600 font-bold">Rising (+12%)</span>
                </div>
                <div className="flex justify-between items-center py-2 border-b border-gray-50">
                  <span className="text-gray-500 text-sm">Job Openings</span>
                  <span className="text-gray-900 font-bold">14.2k</span>
                </div>
                <div className="flex justify-between items-center py-2">
                  <span className="text-gray-500 text-sm">Learning Complexity</span>
                  <div className="flex gap-1">
                    <div className="w-3 h-3 bg-blue-600 rounded-full"></div>
                    <div className="w-3 h-3 bg-blue-600 rounded-full"></div>
                    <div className="w-3 h-3 bg-blue-600 rounded-full"></div>
                    <div className="w-3 h-3 bg-gray-200 rounded-full"></div>
                  </div>
                </div>
              </div>
            </div>

            <div className="bg-gradient-to-br from-indigo-600 to-purple-700 p-6 rounded-2xl text-white shadow-lg">
              <FiZap className="text-yellow-300 mb-4" size={24} />
              <h4 className="font-bold text-lg mb-2">Power Move</h4>
              <p className="text-indigo-100 text-sm leading-relaxed mb-4">
                Based on your profile, learning <strong>PyTorch</strong> will unlock 85% of high-paying AI Engineer roles.
              </p>
              <button className="w-full bg-white text-indigo-700 py-2 rounded-xl font-bold hover:bg-indigo-50 transition-colors">
                Apply This Insight
              </button>
            </div>
          </div>
        </div>
      </main>

      <style>{`
        .animate-fadeIn {
          animation: fadeIn 0.4s ease-out;
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .scrollbar-hide::-webkit-scrollbar {
          display: none;
        }
        .scrollbar-hide {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
      `}</style>
    </div>
  );
};

export default SkillDetails;
